private function isForwardEmulationNeeded(PhpVersion $emulatorPhpVersion): bool {
    return $this->hostPhpVersion->older($emulatorPhpVersion)
        && $this->targetPhpVersion->newerOrEqual($emulatorPhpVersion);
}

private function isReverseEmulationNeeded(PhpVersion $emulatorPhpVersion): bool {
    return $this->hostPhpVersion->newerOrEqual($emulatorPhpVersion)
        && $this->targetPhpVersion->older($emulatorPhpVersion);
}

public function publicUrl(string $path, array $config = []): string
    {
        $this->publicUrlGenerator ??= $this->resolvePublicUrlGenerator()
            ?? throw UnableToGeneratePublicUrl::noGeneratorConfigured($path);
        $config = $this->config->extend($config);

        return $this->publicUrlGenerator->publicUrl(
            $this->pathNormalizer->normalizePath($path),
            $config,
        );
    }

private function retrievePaginatedListing(array $options): Generator
    {
        $resultPaginator = $this->client->getPaginator('ListObjectsV2', $options + $this->options);

        foreach ($resultPaginator as $result) {
            yield from ($result->get('CommonPrefixes') ?? []);
            yield from ($result->get('Contents') ?? []);
        }
    }

public function fileExists(string $path): bool
    {
        return array_key_exists($this->preparePath($path), $this->files);
    }

    public function write(string $path, string $contents, Config $config): void
    {
        $path = $this->preparePath($path);
        $file = $this->files[$path] = $this->files[$path] ?? new InMemoryFile();
        $file->updateContents($contents, $config->get('timestamp'));

        $visibility = $config->get(Config::OPTION_VISIBILITY, $this->defaultVisibility);
        $file->setVisibility($visibility);
    }

foreach ($commandServices as $id => $commands) {
    $definition = $container->getDefinition($id);
    $class = $container->getParameterBag()->resolveValue($definition->getClass());

    if (!$r = $container->getReflectionClass($class)) {
        throw new InvalidArgumentException(\sprintf('Class "%s" used for service "%s" cannot be found.', $class, $id));
    }

    foreach ($commands as $tags) {
        $this->registerCommand($container, $r, $id, $class, $tags, $definition, $serviceIds, $lazyCommandMap, $lazyCommandRefs);
    }
}

if ('' !== $ldapBadge->getSearchDn() && '' !== $ldapBadge->getSearchPassword()) {
    try {
        $ldap->bind($ldapBadge->getSearchDn(), $ldapBadge->getSearchPassword());
    } catch (InvalidCredentialsException) {
        throw new InvalidSearchCredentialsException();
    }
} else {
    throw new LogicException('Using the "query_string" config without using a "search_dn" and a "search_password" is not supported.');
}

if ($composer) {
    $archiveManager = $composer->getArchiveManager();
} else {
    $factory = new Factory;
    $process = new ProcessExecutor();
    $httpDownloader = Factory::createHttpDownloader($io, $config);
    $downloadManager = $factory->createDownloadManager($io, $config, $httpDownloader, $process);
    $archiveManager = $factory->createArchiveManager($config, $downloadManager, new Loop($httpDownloader, $process));
}

if ($composer = $this->tryComposer()) {
    $localRepo = $composer->getRepositoryManager()->getLocalRepository();
    $repo = new CompositeRepository(array_merge([$localRepo], $composer->getRepositoryManager()->getRepositories()));
    $minStability = $composer->getPackage()->getMinimumStability();
} else {
    $defaultRepos = RepositoryFactory::defaultReposWithDefaultManager($io);
    $io->writeError('No composer.json found in the current directory, searching packages from ' . implode(', ', array_keys($defaultRepos)));
    $repo = new CompositeRepository($defaultRepos);
    $minStability = 'stable';
}

if ($input->getOption('locked')) {
    if (!$composer->getLocker()->isLocked()) {
        throw new \UnexpectedValueException('Valid composer.json and composer.lock files are required to run this command with --locked');
    }
    $locker = $composer->getLocker();

    return $locker->getLockedRepository(!$input->getOption('no-dev'))->getPackages();
}

public function addMapping(string $subscriberInterface, string $eventClass): void
    {
        $this->ensureSubscriberInterfaceExists($subscriberInterface);
        $this->ensureSubscriberInterfaceExtendsInterface($subscriberInterface);
        $this->ensureEventClassExists($eventClass);
        $this->ensureEventClassImplementsEventInterface($eventClass);
        $this->ensureSubscriberWasNotAlreadyRegistered($subscriberInterface);
        $this->ensureEventWasNotAlreadyAssigned($eventClass);

        $this->mapping[$subscriberInterface] = $eventClass;
    }

public function toArray(): array
    {
        return [
            'message' => $this->message,
            'context' => $this->context,
            'level' => $this->level->value,
            'level_name' => $this->level->getName(),
            'channel' => $this->channel,
            'datetime' => $this->datetime,
            'extra' => $this->extra,
        ];
    }

if ($from === $to) {
    $resolutionStrategy = $config->get(Config::OPTION_MOVE_IDENTICAL_PATH, ResolveIdenticalPathConflict::TRY);

    if ($resolutionStrategy === ResolveIdenticalPathConflict::FAIL) {
        throw UnableToMoveFile::sourceAndDestinationAreTheSame($source, $destination);
    } elseif ($resolutionStrategy === ResolveIdenticalPathConflict::IGNORE) {
        return;
    }
}

private function guardAgainstInvalidMount(mixed $key, mixed $filesystem): void
    {
        if ( ! is_string($key)) {
            throw UnableToMountFilesystem::becauseTheKeyIsNotValid($key);
        }

        if ( ! $filesystem instanceof FilesystemOperator) {
            throw UnableToMountFilesystem::becauseTheFilesystemWasNotValid($filesystem);
        }
    }

protected function deleteFileInfoObject(SplFileInfo $file): bool
    {
        switch ($file->getType()) {
            case 'dir':
                return @rmdir((string) $file->getRealPath());
            case 'link':
                return @unlink((string) $file->getPathname());
            default:
                return @unlink((string) $file->getRealPath());
        }
    }

if (array_is_list($currentValue) && array_is_list($value)) {
    // Both are lists, merge them
    $value = array_merge($currentValue, $value);
} elseif (!array_is_list($currentValue) && !array_is_list($value)) {
    // Both are associative arrays (objects), merge them
    $value = $value + $currentValue;
} else {
    throw new \RuntimeException('Cannot merge array and object for '.$settingKey);
}

if (!self::$hasZipArchive && !self::$unzipCommands) {
    // php.ini path is added to the error message to help users find the correct file
    $iniMessage = IniHelper::getMessage();
    if ($procOpenMissing) {
        $error = "The zip extension is missing and unzip/7z commands cannot be called as proc_open is disabled, skipping.\n" . $iniMessage;
    } else {
        $error = "The zip extension and unzip/7z commands are both missing, skipping.\n" . $iniMessage;
    }

    throw new \RuntimeException($error);
}

foreach ($discoverableConfigNames as $discoverableConfigName) {
	$discoverableConfigFile = $currentWorkingDirectory . DIRECTORY_SEPARATOR . $discoverableConfigName;
	if (is_file($discoverableConfigFile)) {
		$projectConfigFile = $discoverableConfigFile;
		$errorOutput->writeLineFormatted(sprintf('Note: Using configuration file %s.', $projectConfigFile));
		break;
	}
}

while (false !== $i = strrpos($parentLocale, '_')) {
    $parentLocale = substr($parentLocale, 0, $i);
    $parentMaps = $mapsByLocale[$parentLocale] ?? [];
    foreach ($parentMaps as $codePointsCount => $parentMap) {
        // Ensuring the result map contains all the emojis from the parent map
        // if not already defined by the current locale
        $localeMaps[$codePointsCount] = [...$parentMap, ...$localeMaps[$codePointsCount] ?? []];
    }
}

foreach ($definedFunctionNames as $definedFunctionName) {
    if (false !== $namespaceSeparatorIndex = strrpos($definedFunctionName, '\\')) {
        $definedFunctionNameBasename = substr($definedFunctionName, $namespaceSeparatorIndex + 1);
    } else {
        $definedFunctionNameBasename = $definedFunctionName;
    }

    if ($definedFunctionNameBasename === $functionName) {
        $candidates[] = '\\'.$definedFunctionName;
    }
}

if ('deprecated' === $key) {
    if (!isset($value['package'])) {
        throw new \InvalidArgumentException(\sprintf('The routing file "%s" must specify the attribute "package" of the "deprecated" option for "%s".', $path, $name));
    }

    if (!isset($value['version'])) {
        throw new \InvalidArgumentException(\sprintf('The routing file "%s" must specify the attribute "version" of the "deprecated" option for "%s".', $path, $name));
    }
}

if (null !== $type = $this->getType($resolvedClass, $attribute)) {
    try {
        $value = $this->validateAndDenormalize($type, $resolvedClass, $attribute, $value, $format, $attributeContext);
    } catch (NotNormalizableValueException $exception) {
        if (isset($context['not_normalizable_value_exceptions'])) {
            $context['not_normalizable_value_exceptions'][] = $exception;
            continue;
        }
        throw $exception;
    }
}

try {
    $value = $this->validateAndDenormalize($type, $resolvedClass, $attribute, $value, $format, $attributeContext);
} catch (NotNormalizableValueException $exception) {
    if (isset($context['not_normalizable_value_exceptions'])) {
        $context['not_normalizable_value_exceptions'][] = $exception;
        continue;
    }
    throw $exception;
}

if (null === $this->devMode) {
    // we assume no-dev mode if no vendor dir is present or it is too old to contain dev information
    $this->devMode = false;

    $installedJson = new JsonFile($config->get('vendor-dir').'/composer/installed.json');
    if ($installedJson->exists()) {
        $installedJson = $installedJson->read();
        if (isset($installedJson['dev'])) {
            $this->devMode = $installedJson['dev'];
        }
    }
}

if (isset($options['progress'])) {
    $progress = $options['progress'];
    if (!\is_callable($progress)) {
        throw new \InvalidArgumentException('progress client option must be callable');
    }
    $conf[\CURLOPT_NOPROGRESS] = false;
    $conf[\CURLOPT_PROGRESSFUNCTION] = static function ($resource, int $downloadSize, int $downloaded, int $uploadSize, int $uploaded) use ($progress) {
        $progress($downloadSize, $downloaded, $uploadSize, $uploaded);
    };
}

if ($varIsNull->yes()) {
	// Arguments are never evaluated when the var is always null.
	$scope = $scopeBeforeNullsafe;
} elseif ($varIsNull->maybe()) {
	// Arguments might not be evaluated (short-circuit).
	// Merge with the original scope so variables assigned in arguments become "maybe defined".
	$scope = $scope->mergeWith($scopeBeforeNullsafe);
}

if (function_exists('openssl_get_cipher_methods')) {
	// openssl_get_cipher_methods() reports algorithms that are not actually
	// supported on PHP 8.0-8.4 due to https://github.com/php/php-src/issues/19994
	// Filter by actually testing each algorithm with openssl_cipher_iv_length().
	$methods = array_values(array_filter(
		openssl_get_cipher_methods(true),
		static fn (string $algorithm): bool => @openssl_cipher_iv_length($algorithm) !== false,
	));
}

if ($this->useShortAttachment) {
    $attachment['fields'][] = $this->generateAttachmentField(
        $key,
        $recordData[$key]
    );
} else {
    // Add all extra fields as individual fields in attachment
    $attachment['fields'] = array_merge(
        $attachment['fields'],
        $this->generateAttachmentFields($recordData[$key])
    );
}

try {
    $params[$paramName] = $this->denormalizeParameter($reflectionClass, $constructorParameter, $paramName, $parameterData, $attributeContext, $format);
} catch (NotNormalizableValueException $exception) {
    if (!isset($context['not_normalizable_value_exceptions'])) {
        throw $exception;
    }

    $context['not_normalizable_value_exceptions'][] = $exception;
    $params[$paramName] = $parameterData;
}

foreach ($config['original_files'] as $originalFilePath) {
    $translationFilePaths = findTranslationFiles($originalFilePath, $config['locale_to_analyze']);
    $translationStatus = calculateTranslationStatus($originalFilePath, $translationFilePaths);

    $totalMissingTranslations += array_sum(array_map(static fn ($translation) => count($translation['missingKeys']), array_values($translationStatus)));
    $totalTranslationMismatches += array_sum(array_map(static fn ($translation) => count($translation['mismatches']), array_values($translationStatus)));

    printTranslationStatus($originalFilePath, $translationStatus, $config['verbose_output'], $config['include_completed_languages']);
}

foreach ($packages as $package) {
    $matchingEntries = $filterAuditor->getMatchingAuditEntries($package, $filterResult['filter'], $policyConfig);
    foreach ($matchingEntries as $entry) {
        $filteredPackages[$package->getName()][] = $entry;

        if (isset($failingListNames[$entry->listName])) {
            $filteredCount++;
        }
    }
}

if (!file_exists($target)) {
    // create minimal valid ZIP file (Empty Central Directory + End of Central Directory record)
    $eocd = pack(
        'VvvvvVVv',
        0x06054b50,  // End of central directory signature
        0,           // Number of this disk
        0,           // Disk where central directory starts
        0,           // Number of central directory records on this disk
        0,           // Total number of central directory records
        0,           // Size of central directory (bytes)
        0,           // Offset of start of central directory
        0            // Comment length
    );
    file_put_contents($target, $eocd);
}

if ($normalizedParts !== $futureParts) {
    Deprecation::trigger(
        'doctrine/dbal',
        'https://github.com/doctrine/dbal/pull/6592',
        'Relying on implicitly quoted identifiers preserving their original case is deprecated. '
            . 'The current name %s will become %s in 5.0. '
            . 'Please quote the name if the case needs to be preserved.',
        $name,
        implode('.', array_map([$platform, 'quoteSingleIdentifier'], $futureParts)),
    );
}

if ($inFunctionCallsStackCount > 0) {
	[, $inParameter] = $scope->inFunctionCallsStack[$inFunctionCallsStackCount - 1];
	if ($inParameter !== null) {
		$callableParameters = $this->nodeScopeResolver->createCallableParameters($scope, $expr, null, $inParameter->getType());
		$nativeType = $inParameter instanceof ExtendedParameterReflection ? $inParameter->getNativeType() : $inParameter->getType();
		$nativeCallableParameters = $this->nodeScopeResolver->createNativeCallableParameters($scope, $expr, null, $nativeType);
	}
}

if (isset($setHookMethodReflectionParameters[0])) {
	$setHookMethodReflectionParameter = $setHookMethodReflectionParameters[0];
	$setHookMethodReflectionParameterPhpDocType = $setHookMethodReflectionParameter->getPhpDocType();
	if (
		$setHookMethodReflectionParameterPhpDocType instanceof MixedType
		&& !$setHookMethodReflectionParameterPhpDocType instanceof TemplateMixedType
		&& !$setHookMethodReflectionParameterPhpDocType->isExplicitMixed()
	) {
		$setHook = $setHook->changePropertySetHookPhpDocType($setHookMethodReflectionParameter->getName(), $phpDocType);
	}
}

if ($this->isUnsealed()->yes() && $this->unsealed !== null) {
	$unsealedKeyType = $this->unsealed[0];
	if ($unsealedKeyType instanceof MixedType && !$unsealedKeyType instanceof TemplateMixedType) {
		$unsealedKeyType = (new BenevolentUnionType([new IntegerType(), new StringType()]))->toArrayKey();
	} elseif ($unsealedKeyType instanceof StrictMixedType && !$unsealedKeyType instanceof TemplateStrictMixedType) {
		$unsealedKeyType = (new BenevolentUnionType([new IntegerType(), new StringType()]))->toArrayKey();
	}
	$keyType = TypeCombinator::union($keyType, $unsealedKeyType);
}

if ($this->isUnsealed()->yes() && $this->unsealed !== null) {
	$unsealedKeyType = $this->unsealed[0];
	if ($unsealedKeyType instanceof MixedType && !$unsealedKeyType instanceof TemplateMixedType) {
		$unsealedKeyType = (new BenevolentUnionType([new IntegerType(), new StringType()]))->toArrayKey();
	} elseif ($unsealedKeyType instanceof StrictMixedType && !$unsealedKeyType instanceof TemplateStrictMixedType) {
		$unsealedKeyType = (new BenevolentUnionType([new IntegerType(), new StringType()]))->toArrayKey();
	}
	$keyTypes[] = $unsealedKeyType;
}

if ($index >= $firstOptional) {
    // Enclose each optional token in a subpattern to make it optional.
    // "?:" means it is non-capturing, i.e. the portion of the subject string that
    // matched the optional subpattern is not passed back.
    $regexp = "(?:$regexp";
    $nbTokens = \count($tokens);
    if ($nbTokens - 1 == $index) {
        // Close the optional subpatterns
        $regexp .= str_repeat(')?', $nbTokens - $firstOptional - (0 === $firstOptional ? 1 : 0));
    }
}

if (\count($context['not_normalizable_value_exceptions']) === $collectedErrorCountBeforeConstructor) {
    $context['not_normalizable_value_exceptions'][] = NotNormalizableValueException::createForUnexpectedDataType(
        \sprintf('Failed to create an instance of "%s" from constructor: %s', $class, $e->getMessage()),
        null,
        ['unknown'],
        $context['deserialization_path'] ?? null,
        false,
        0,
        $e,
    );
}

if (
    (!str_starts_with($pattern, $dirMatch) && !str_starts_with($dirMatch, $pattern))
    && (
        // only check dirMatchNormalized if it is actually different from dirMatch otherwise there is no point
        !$isSymlink
        || (!str_starts_with($pattern, $dirMatchNormalized) && !str_starts_with($dirMatchNormalized, $pattern))
    )
) {
    unset($excluded[$index]);
}

foreach ($this->getAdditionalAnalysedFiles() as $additionalAnalysedFile) {
	$normalizedAdditionalFilePath = $fileHelper->normalizePath($additionalAnalysedFile);
	if (!isset($actualJson['files'][$normalizedAdditionalFilePath])) {
		continue;
	}

	$messagesBeforeDiffing = array_merge($messagesBeforeDiffing, $actualJson['files'][$normalizedAdditionalFilePath]['messages']);
}

if (null === $label) {
    // If the labels are null, use the original choice key by default
    $label = (string) $key;
} elseif (false !== $label) {
    // If "choice_label" is set to false and "expanded" is true, the value false
    // should be passed on to the "label" option of the checkboxes/radio buttons
    $dynamicLabel = $label($choice, $key, $value);

    if (false === $dynamicLabel) {
        $label = false;
    } elseif ($dynamicLabel instanceof TranslatableInterface) {
        $label = $dynamicLabel;
    } else {
        $label = (string) $dynamicLabel;
    }
}

if ($totalFlexWeight > 0 && $remainingColumns > 0) {
    // Last flex child gets whatever is left to avoid rounding errors
    ++$flexAllocated;
    if ($flexAllocated === $flexCount) {
        $allocated = $remainingColumns - $flexColumnsUsed;
    } else {
        $allocated = (int) floor($remainingColumns * $flexWeights[$index] / $totalFlexWeight);
    }
} else {
    $allocated = 0;
}

if ($type instanceof GenericObjectType || $type instanceof GenericStaticType) {
	$resolvedType = TemplateTypeHelper::resolveToBounds($type);
	if (!$resolvedType instanceof GenericObjectType && !$resolvedType instanceof GenericStaticType) {
		throw new ShouldNotHappenException();
	}
	$genericObjectTypes[] = $resolvedType;
	$traverse($type);
	return $type;
}

if ($preserveTaggedUnions && $emptyArray instanceof ConstantArrayType) {
	// Let the empty array participate in merging — the passes below will absorb
	// it into any array that already accepts [] (all-optional keys, compatible
	// unsealed extras). If no such array exists, it remains as-is in the result.
	$arraysToProcess[] = $emptyArray;
} else {
	$newArrays[] = $emptyArray;
}
